sp_instance.widget_parameters:
{
	"html": {
		"value": "<style>
  /* إعادة تعيين هوامش الجسم لضمان عدم وجود فراغات جانبية */
  html, body {
    margin: 0;
    padding: 0;
    width: 100%;
    overflow-x: hidden;
  }

  .how-it-works-section {
    width: 100%;
    max-width: 100%;
    margin: 0;
    padding: 60px 20px; /* مسافة داخلية من الأعلى/الأسفل ومن الجوانب بحيث لا تلتصق الكروت بالحافة */
    text-align: center;
    background-color: #F8FAFC; /* لون خلفية خفيف اختياري */
    box-sizing: border-box;
  }

  .section-title {
    font-size: 28px;
    font-weight: 700;
    color: #0F172A;
    margin-bottom: 40px;
  }

  .steps-container {
    display: flex;
    justify-content: center;
    gap: 40px;
    flex-wrap: wrap;
    width: 100%;
  }

  .step-card {
    background: #FFFFFF;
    border-radius: 24px;
    padding: 30px 25px;
    flex: 1 1 0; /* يسمح للكروت بالتمدد لتوزيع المساحة بالتساوي */
    min-width: 220px; /* يحدد أصغر عرض مقبول */
    max-width: 320px; /* يحدد أكبر عرض لمنع التمدد الزائد */
    text-align: center;
    border: 1px solid #E2E8F0;
    transition: all 0.25s ease;
    box-sizing: border-box;
  }

  /* لضمان أن الصف يحتوي على 3 كروت موزعة بالتساوي حتى على الشاشات العريضة */
  @media (min-width: 1000px) {
    .steps-container {
      justify-content: space-evenly;
    }
    .step-card {
      flex: 1;
    }
  }

  /* باقي الأنماط كما هي */
  .step-card:hover {
    transform: translateY(-5px);
    box-shadow: 0 12px 24px rgba(0, 0, 0, 0.08);
    border-color: #E60000;
  }

  .step-number {
    width: 60px;
    height: 60px;
    background: #FEF2F2;
    color: #E60000;
    font-size: 28px;
    font-weight: 800;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    margin: 0 auto 20px;
    transition: all 0.2s;
  }

  .step-card:hover .step-number {
    background: #E60000;
    color: white;
  }

  .step-card h3 {
    font-size: 20px;
    font-weight: 700;
    margin-bottom: 10px;
    color: #0F172A;
  }

  .step-card p {
    font-size: 14px;
    color: #64748B;
    line-height: 1.4;
  }

  @media (max-width: 768px) {
    .how-it-works-section {
      padding: 40px 15px;
    }
    .steps-container {
      gap: 20px;
    }
    .step-card {
      min-width: 180px;
      padding: 20px 15px;
    }
    .step-number {
      width: 50px;
      height: 50px;
      font-size: 24px;
    }
    .step-card h3 {
      font-size: 18px;
    }
  }
</style>
<div class="how-it-works-section">
<div class="section-title">How It Works</div>
<div class="steps-container">
<div class="step-card">
<div class="step-number">1</div>
<h3>Select Medicine</h3>
<p>Browse or search for your medicine</p>
</div>
<div class="step-card">
<div class="step-number">2</div>
<h3>Place Order</h3>
<p>Fill the form and get approval</p>
</div>
<div class="step-card">
<div class="step-number">3</div>
<h3>Pickup</h3>
<p>Collect from pharmacy</p>
</div>
</div>
</div>",
